// @venom: browser
import React from "../jsx-runtime"; import type { ExecutiveReport } from "../data/types";
interface ReportsProps { report:ExecutiveReport; onRegenerate:()=>void; }
export default function ReportsPanel({report,onRegenerate}:ReportsProps){ return <section className="reports-layout"><article className="report-hero"><p className="eyebrow">Protected executive intelligence</p><h2>{report.headline}</h2><p>{report.summary}</p><div className="report-actions"><button className="primary-button" onClick={onRegenerate}>Regenerate report</button><button className="secondary-button">Export PDF</button></div><div className="checksum">Integrity checksum <code>{report.checksum}</code></div></article><article className="panel priorities"><div className="panel-heading"><h2>Immediate priorities</h2></div><ol>{report.priorities.map((item,index)=><li><span>{index+1}</span><div><strong>{item}</strong><small>Recommended by protected report model</small></div></li>)}</ol></article><article className="panel report-library"><div className="panel-heading"><h2>Report library</h2></div>{["Board risk briefing","Operational resilience summary","Regional exposure analysis","Capacity planning memo"].map((name,index)=><div className="report-row"><span className="report-doc">▤</span><div><strong>{name}</strong><small>Generated {index+1} day{index?"s":""} ago</small></div><button>Open</button></div>)}</article></section>; }
